import{_ as a,o as d,c as e,ag as r}from"./chunks/framework.Vng7Hdlh.js";const u=JSON.parse('{"title":"14. AIアシスタント","description":"","frontmatter":{},"headers":[],"relativePath":"tenant/14-ai.md","filePath":"tenant/14-ai.md"}'),i={name:"tenant/14-ai.md"};function l(h,t,o,n,s,b){return d(),e("div",null,[...t[0]||(t[0]=[r('<h1 id="_14-aiアシスタント" tabindex="-1">14. AIアシスタント <a class="header-anchor" href="#_14-aiアシスタント" aria-label="Permalink to &quot;14. AIアシスタント&quot;">​</a></h1><p>管理ダッシュボードの「AIアシスタント」タブでは、AIを活用したSNS投稿生成・売上分析・競合調査・需要予測の機能を利用できます。マネージャー以上のロールで利用できます。</p><p>AIにはGemini 2.0 Flash APIが使用されており、APIキーはPOSLA運営が一括管理しているため、テナント側での設定は不要です。</p><div class="info custom-block"><p class="custom-block-title">サーバープロキシ経由の呼び出し（P1-6）</p><p>管理画面のAIアシスタント機能は、APIキーがブラウザに渡らないよう<strong>サーバー側プロキシ経由</strong>でGemini APIを呼び出します。</p><ul><li>フロントエンド（<code>public/admin/js/ai-assistant.js</code>）→ サーバー（<code>api/store/ai-generate.php</code>）→ Gemini API</li><li>ブラウザのDevToolsでAPIキーが見えることはありません</li><li>AIサービスが利用できない場合は「AIサービスは現在利用できません。POSLA運営にお問い合わせください」と表示されます</li></ul></div><h2 id="_14-1-sns投稿生成" tabindex="-1">14.1 SNS投稿生成 <a class="header-anchor" href="#_14-1-sns投稿生成" aria-label="Permalink to &quot;14.1 SNS投稿生成&quot;">​</a></h2><p>InstagramやX（旧Twitter）向けの投稿文を自動生成します。</p><h3 id="入力フィールド" tabindex="-1">入力フィールド <a class="header-anchor" href="#入力フィールド" aria-label="Permalink to &quot;入力フィールド&quot;">​</a></h3><table tabindex="0"><thead><tr><th>フィールド</th><th>説明</th></tr></thead><tbody><tr><td>店舗名</td><td>投稿に含める店舗名</td></tr><tr><td>おすすめメニュー</td><td>紹介するメニュー品目</td></tr><tr><td>アピールポイント</td><td>強調したいポイント</td></tr></tbody></table><h3 id="プラットフォーム別の生成" tabindex="-1">プラットフォーム別の生成 <a class="header-anchor" href="#プラットフォーム別の生成" aria-label="Permalink to &quot;プラットフォーム別の生成&quot;">​</a></h3><table tabindex="0"><thead><tr><th>プラットフォーム</th><th>特徴</th></tr></thead><tbody><tr><td>Instagram</td><td>絵文字使用、ハッシュタグ5つ以上、複数行の読みやすい形式</td></tr><tr><td>X（Twitter）</td><td>テキストのみ、簡潔な文字数に収まる形式</td></tr></tbody></table><h3 id="aiパラメータ" tabindex="-1">AIパラメータ <a class="header-anchor" href="#aiパラメータ" aria-label="Permalink to &quot;AIパラメータ&quot;">​</a></h3><table tabindex="0"><thead><tr><th>パラメータ</th><th>値</th></tr></thead><tbody><tr><td>モデル</td><td>Gemini 2.0 Flash</td></tr><tr><td>Temperature</td><td>0.8（クリエイティブ）</td></tr><tr><td>最大出力トークン</td><td>1024</td></tr></tbody></table><hr><h2 id="_14-2-売上分析" tabindex="-1">14.2 売上分析 <a class="header-anchor" href="#_14-2-売上分析" aria-label="Permalink to &quot;14.2 売上分析&quot;">​</a></h2><p>店舗の売上データをAIが分析し、トレンドや改善点を提案します。</p><h3 id="分析の流れ" tabindex="-1">分析の流れ <a class="header-anchor" href="#分析の流れ" aria-label="Permalink to &quot;分析の流れ&quot;">​</a></h3><ol><li>AIアシスタントの「売上分析」を選択します</li><li>売上レポートAPIからデータが自動取得されます <ul><li>トップ10品目</li><li>時間帯別売上</li><li>サービス時間データ</li></ul></li><li>AIが分析結果を返します</li></ol><h3 id="aiからの出力" tabindex="-1">AIからの出力 <a class="header-anchor" href="#aiからの出力" aria-label="Permalink to &quot;AIからの出力&quot;">​</a></h3><ul><li>売上トレンドの分析</li><li>ベストセラー品目の特定</li><li>改善が必要な領域の指摘</li><li>具体的な改善提案</li></ul><h3 id="aiパラメータ-1" tabindex="-1">AIパラメータ <a class="header-anchor" href="#aiパラメータ-1" aria-label="Permalink to &quot;AIパラメータ&quot;">​</a></h3><table tabindex="0"><thead><tr><th>パラメータ</th><th>値</th></tr></thead><tbody><tr><td>Temperature</td><td>0.5（分析向け、やや低め）</td></tr><tr><td>最大出力トークン</td><td>1024</td></tr></tbody></table><hr><h2 id="_14-3-競合調査" tabindex="-1">14.3 競合調査 <a class="header-anchor" href="#_14-3-競合調査" aria-label="Permalink to &quot;14.3 競合調査&quot;">​</a></h2><p>周辺の競合店舗をGoogle Maps/Places APIで分析し、差別化戦略を提案します。</p><h3 id="分析内容" tabindex="-1">分析内容 <a class="header-anchor" href="#分析内容" aria-label="Permalink to &quot;分析内容&quot;">​</a></h3><ul><li>近隣店舗の価格帯</li><li>評価（レーティング）</li><li>推定客数</li><li>競合との差別化ポイント</li></ul><h3 id="aiからの出力-1" tabindex="-1">AIからの出力 <a class="header-anchor" href="#aiからの出力-1" aria-label="Permalink to &quot;AIからの出力&quot;">​</a></h3><ul><li>競合店舗名と数値データを含む分析</li><li>今週中に実行可能な3つの具体的アクション</li><li>店舗名や数値を含む具体的な提案</li></ul><hr><h2 id="_14-4-需要予測" tabindex="-1">14.4 需要予測 <a class="header-anchor" href="#_14-4-需要予測" aria-label="Permalink to &quot;14.4 需要予測&quot;">​</a></h2><p>過去の売上データとレシピ情報を組み合わせて、今後の需要を予測します。</p><h3 id="データソース" tabindex="-1">データソース <a class="header-anchor" href="#データソース" aria-label="Permalink to &quot;データソース&quot;">​</a></h3><ul><li>過去7日間の売上データ</li><li>品目別の販売数量</li><li>曜日別パターン</li><li>レシピ情報（原材料の使用量）</li></ul><h3 id="aiからの出力-2" tabindex="-1">AIからの出力 <a class="header-anchor" href="#aiからの出力-2" aria-label="Permalink to &quot;AIからの出力&quot;">​</a></h3><table tabindex="0"><thead><tr><th>セクション</th><th>内容</th></tr></thead><tbody><tr><td>日別需要予測</td><td>今後の日ごとの品目別販売予測</td></tr><tr><td>原材料発注推奨</td><td>不足見込みの原材料と推奨発注量</td></tr><tr><td>低在庫アラート</td><td>閾値を下回る見込みの原材料</td></tr><tr><td>ポーション調整</td><td>使い切り・廃棄削減のための提案</td></tr></tbody></table><h3 id="aiパラメータ-2" tabindex="-1">AIパラメータ <a class="header-anchor" href="#aiパラメータ-2" aria-label="Permalink to &quot;AIパラメータ&quot;">​</a></h3><table tabindex="0"><thead><tr><th>パラメータ</th><th>値</th></tr></thead><tbody><tr><td>Temperature</td><td>0.5（分析向け）</td></tr><tr><td>最大出力トークン</td><td>8192（詳細な予測のため大きめ）</td></tr></tbody></table><hr><h2 id="_14-5-aiウェイター-お客さん向け" tabindex="-1">14.5 AIウェイター（お客さん向け） <a class="header-anchor" href="#_14-5-aiウェイター-お客さん向け" aria-label="Permalink to &quot;14.5 AIウェイター（お客さん向け）&quot;">​</a></h2><p>セルフオーダー画面には、お客さんが利用できるAIチャットボット「AIウェイター」が搭載されています。</p><h3 id="表示" tabindex="-1">表示 <a class="header-anchor" href="#表示" aria-label="Permalink to &quot;表示&quot;">​</a></h3><ul><li>画面右下にオレンジ色のフローティングボタン（FAB）として表示されます</li><li>タップするとチャットパネル（320px × 420px）が開きます</li></ul><h3 id="機能" tabindex="-1">機能 <a class="header-anchor" href="#機能" aria-label="Permalink to &quot;機能&quot;">​</a></h3><table tabindex="0"><thead><tr><th>機能</th><th>説明</th></tr></thead><tbody><tr><td>メニュー相談</td><td>「辛くないおすすめは？」「子供向けメニューは？」などの質問に回答</td></tr><tr><td>おすすめ提案</td><td>AIがメニューからおすすめ品目をカード形式で提案</td></tr><tr><td>カートに追加</td><td>提案されたメニューを直接カートに追加</td></tr><tr><td>音声入力</td><td>Web Speech APIによる音声入力（日本語）</td></tr><tr><td>会話履歴</td><td>最大10往復の会話を保持</td></tr></tbody></table><h3 id="チャットパネルの構成" tabindex="-1">チャットパネルの構成 <a class="header-anchor" href="#チャットパネルの構成" aria-label="Permalink to &quot;チャットパネルの構成&quot;">​</a></h3><table tabindex="0"><thead><tr><th>要素</th><th>説明</th></tr></thead><tbody><tr><td>ウェルカムメッセージ</td><td>最初に表示される案内と質問例</td></tr><tr><td>メッセージ履歴</td><td>ユーザーとAIのチャット履歴</td></tr><tr><td>タイピングインジケーター</td><td>AI応答中のアニメーション</td></tr><tr><td>おすすめカード</td><td>品名、価格、「カートに追加」ボタン</td></tr><tr><td>テキスト入力欄</td><td>—</td></tr><tr><td>音声入力ボタン</td><td>マイクアイコン</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">AIウェイターの利用条件</p><p>AIウェイターは、POSLA運営でGemini APIキーが設定されている場合に自動的に有効になります。APIの利用可否はシステムが自動チェックし、利用できない場合はボタンが表示されません。</p></div>',47)])])}const A=a(i,[["render",l]]);export{u as __pageData,A as default};
